  ('00000000-0000-0000-0004-011006001000', '00000000-0000-0000-0003-011006000000', 'Takes a focused history, performs an appropriate examination and orders appropriate investigations.', 1),
  ('00000000-0000-0000-0004-011006002000', '00000000-0000-0000-0003-011006000000', 'Formulates an appropriate and individualised management plan, taking into account a patient''s preferences, including complementary therapies and lifestyle changes.', 2),
