  -- CiP_11_KS07 (3 descriptors)
  ('00000000-0000-0000-0004-011007001000', '00000000-0000-0000-0003-011007000000', 'Takes a focused history, performs an appropriate examination and orders appropriate investigations.', 1),
  ('00000000-0000-0000-0004-011007002000', '00000000-0000-0000-0003-011007000000', 'Is able to interpret results to plan effective care and counsel someone about their options, including where they can be referred and alternative ways to conceive.', 2),
  ('00000000-0000-0000-0004-011007003000', '00000000-0000-0000-0003-011007000000', 'Understands the ethical issues surrounding IVF treatment.', 3),
  -- CiP_11_KS08 (8 descriptors)
  ('00000000-0000-0000-0004-011008001000', '00000000-0000-0000-0003-011008000000', 'Takes a focused history, performs an appropriate examination and orders appropriate investigations.', 1),
  ('00000000-0000-0000-0004-011008002000', '00000000-0000-0000-0003-011008000000', 'Offers advice to someone about contraceptive methods and understands factors which affect their choice of contraception, including comorbidities, patient preference, failure rates, etc.', 2),
  ('00000000-0000-0000-0004-011008003000', '00000000-0000-0000-0003-011008000000', 'Demonstrates the ability to administer/fit different contraceptive methods.', 3),
  ('00000000-0000-0000-0004-011008004000', '00000000-0000-0000-0003-011008000000', 'Demonstrates the ability to manage unplanned pregnancies, including medical and surgical abortion*', 4),
  ('00000000-0000-0000-0004-011008005000', '00000000-0000-0000-0003-011008000000', 'Is aware of alternative sources of support and follow-up for patients, particularly in cases of unplanned pregnancy and termination of pregnancy.', 5),
  ('00000000-0000-0000-0004-011008006000', '00000000-0000-0000-0003-011008000000', 'Offers sexual health screening advice and provides appropriate referral to genitourinary medicine (GUM) services to manage sexually transmitted infections.', 6),
  ('00000000-0000-0000-0004-011008007000', '00000000-0000-0000-0003-011008000000', 'Identifies psychosexual problems, explores them and can refers someone to specialist services where available.', 7),
  ('00000000-0000-0000-0004-011008008000', '00000000-0000-0000-0003-011008000000', 'Recognises the interactions between gynaecological problems and psychosexual problems.* Trainees who have personal beliefs that conflict with the provision of abortion, or for those undertaking training in a place where there are legal restrictions to provision of abortion, see Section 10 of the Definitive Document.', 8),
  -- CiP_11_KS09 (4 descriptors)
  ('00000000-0000-0000-0004-011009001000', '00000000-0000-0000-0003-011009000000', 'Demonstrates the ability to assess a postoperative patient and makes sure they have adequate/optimum analgesia.', 1),
  ('00000000-0000-0000-0004-011009002000', '00000000-0000-0000-0003-011009000000', 'Recognises non-gynaecological causes of pain.', 2),
  ('00000000-0000-0000-0004-011009003000', '00000000-0000-0000-0003-011009000000', 'Demonstrates the ability to manage pain due to common gastrointestinal and urological conditions and to counsel a patient appropriately.', 3),
  ('00000000-0000-0000-0004-011009004000', '00000000-0000-0000-0003-011009000000', 'Recognises when a patient with postoperative pain needs referring to other specialities.', 4),
  -- CiP_12_KS01 (4 descriptors)
  ('00000000-0000-0000-0004-012001001000', '00000000-0000-0000-0003-012001000000', 'Demonstrates the ability to provide preconceptual advice to women and sensitively discuss risks during pregnancy. Uses this to create tailored management plans, in conjunction with other specialties where appropriate.', 1),
  ('00000000-0000-0000-0004-012001002000', '00000000-0000-0000-0003-012001000000', 'Identifies, assesses and manages pre-existing physical and mental health conditions in a pregnant or postnatal woman.', 2),
  ('00000000-0000-0000-0004-012001003000', '00000000-0000-0000-0003-012001000000', 'Understands the impact of pregnancy on disease and of disease on pregnancy.', 3),
  ('00000000-0000-0000-0004-012001004000', '00000000-0000-0000-0003-012001000000', 'Formulates appropriate and individualised management plans for pregnancy, birth and the postnatal period, in consultation with other specialities and obstetric anaesthesia.', 4),
  -- CiP_12_KS02 (9 descriptors)
  ('00000000-0000-0000-0004-012002001000', '00000000-0000-0000-0003-012002000000', 'Prescribes safely and understands the challenge of safe prescribing in pregnancy, making changes to medications where necessary.', 1),
  ('00000000-0000-0000-0004-012002002000', '00000000-0000-0000-0003-012002000000', 'Demonstrates the ability to recognise when conditions related, and unrelated, to pregnancy develop.', 2),
  ('00000000-0000-0000-0004-012002003000', '00000000-0000-0000-0003-012002000000', 'Offers screening for, and treatment of, maternal infections that can affect fetal wellbeing and development.', 3),
  ('00000000-0000-0000-0004-012002004000', '00000000-0000-0000-0003-012002000000', 'Demonstrates the ability to take a focused history and perform an appropriate physical examination of a pregnant person. Takes into account the physiological and anatomical changes of pregnancy.', 4),
  ('00000000-0000-0000-0004-012002005000', '00000000-0000-0000-0003-012002000000', 'Identifies, assesses and manages both pregnancy-specific and non-specific conditions, and considers the impact on both maternal and fetal health.', 5),
  ('00000000-0000-0000-0004-012002006000', '00000000-0000-0000-0003-012002000000', 'Demonstrates the ability to order and interpret appropriate investigations to monitor conditions during pregnancy.', 6),
  ('00000000-0000-0000-0004-012002007000', '00000000-0000-0000-0003-012002000000', 'Formulates appropriate and tailored management plans for pregnancy and birth.', 7),
  ('00000000-0000-0000-0004-012002008000', '00000000-0000-0000-0003-012002000000', 'Prepares and plans the different options for the birth of a baby in the breech presentation, including using External Cephalic Version (ECV). Doctors who wish to practice using ECV should have three summative competent OSATS.', 8),
  ('00000000-0000-0000-0004-012002009000', '00000000-0000-0000-0003-012002000000', 'Prescribes medications and antimicrobials appropriately, in line with the latest evidence, and reviews and monitors therapeutic interventions.', 9),
  -- CiP_12_KS03 (5 descriptors)
  ('00000000-0000-0000-0004-012003001000', '00000000-0000-0000-0003-012003000000', 'Demonstrates an ability to obtain a focused history, undertake an appropriate examination and order a clinically indicated investigation.', 1),
  ('00000000-0000-0000-0004-012003002000', '00000000-0000-0000-0003-012003000000', 'Facilitates timely and appropriate investigation, management and referral to tertiary centres, if required.', 2),
  ('00000000-0000-0000-0004-012003003000', '00000000-0000-0000-0003-012003000000', 'Demonstrates knowledge and an ability to work within local managed clinical networks.', 3),
  ('00000000-0000-0000-0004-012003004000', '00000000-0000-0000-0003-012003000000', 'Demonstrates the ability to discuss concerns and clinical uncertainties with pregnant person in a sensitive manner.', 4),
  ('00000000-0000-0000-0004-012003005000', '00000000-0000-0000-0003-012003000000', 'Formulates an appropriate and individualised management plans for pregnancy and birth.', 5),
  -- CiP_12_KS04 (4 descriptors)
  ('00000000-0000-0000-0004-012004001000', '00000000-0000-0000-0003-012004000000', 'Demonstrates the ability to effectively and sensitively screen for mental health concerns arising in pregnant people.', 1),
  ('00000000-0000-0000-0004-012004002000', '00000000-0000-0000-0003-012004000000', 'Demonstrates the ability to formulate the initial diagnosis and management of mental health conditions, with appropriate liaison and involvement of mental health services.', 2),
  ('00000000-0000-0000-0004-012004003000', '00000000-0000-0000-0003-012004000000', 'Manages perinatal mental health emergencies in the antenatal and postnatal period effectively.', 3),
  ('00000000-0000-0000-0004-012004004000', '00000000-0000-0000-0003-012004000000', 'Understands the impact that birth, birth trauma and adverse outcomes may have on someone''s future mental health and is able to signpost women and their families to support services.', 4),
  -- CiP_12_KS05 (6 descriptors)
  ('00000000-0000-0000-0004-012005001000', '00000000-0000-0000-0003-012005000000', 'Understands the significant impact that lifestyle factors may have on maternal and fetal health.', 1),
  ('00000000-0000-0000-0004-012005002000', '00000000-0000-0000-0003-012005000000', 'Demonstrates the ability to take a focused history, perform an appropriate examination and to order clinically indicated investigations.', 2),
  ('00000000-0000-0000-0004-012005003000', '00000000-0000-0000-0003-012005000000', 'Sensitively enquires about lifestyle factors to facilitate disclosure.', 3),
  ('00000000-0000-0000-0004-012005004000', '00000000-0000-0000-0003-012005000000', 'Understands and demonstrates the ability to manage pregnancies where lifestyle factors cause complications.', 4),
  ('00000000-0000-0000-0004-012005005000', '00000000-0000-0000-0003-012005000000', 'Formulates appropriate individualised management plans for pregnancy, birth and the postnatal period.', 5),
  ('00000000-0000-0000-0004-012005006000', '00000000-0000-0000-0003-012005000000', 'Uses support services appropriately, according to local provision and taking into account the wishes of the pregnant person and the needs of the fetus/neonate.', 6),
  -- CiP_12_KS06 (5 descriptors)
  ('00000000-0000-0000-0004-012006001000', '00000000-0000-0000-0003-012006000000', 'Identifies risk factors relating to previous pregnancy outcomes and advises women on the best current practice to mitigate risk.', 1),
  ('00000000-0000-0000-0004-012006002000', '00000000-0000-0000-0003-012006000000', 'Can advise pregnant people on the potential impact of the mode of birth and intrapartum interventions on general and pelvic floor health.', 2),
  ('00000000-0000-0000-0004-012006003000', '00000000-0000-0000-0003-012006000000', 'Effectively estimates risks to advise and inform decision making for pregnant person and their families.', 3),
  ('00000000-0000-0000-0004-012006004000', '00000000-0000-0000-0003-012006000000', 'Formulates appropriate and individualised management plans for pregnancy and birth.', 4),
  ('00000000-0000-0000-0004-012006005000', '00000000-0000-0000-0003-012006000000', 'Supports decision making for the pregnant person and their family when a fetal anomaly is identified.', 5),
  -- CiP_12_KS07 (7 descriptors)
  ('00000000-0000-0000-0004-012007001000', '00000000-0000-0000-0003-012007000000', 'Manages a postnatal consultation.', 1),
  ('00000000-0000-0000-0004-012007002000', '00000000-0000-0000-0003-012007000000', 'Demonstrates the ability to sensitively debrief women and their families after an unexpected birth experience or when a baby is admitted to the neonatal unit.', 2),
  ('00000000-0000-0000-0004-012007003000', '00000000-0000-0000-0003-012007000000', 'Advises on the impact of events in this pregnancy on future health and pregnancies.', 3),
  ('00000000-0000-0000-0004-012007004000', '00000000-0000-0000-0003-012007000000', 'Demonstrates the ability to take a focused history, undertake an appropriate physical examination for women who have sustained an OASI and either manage, or refer on to, specialist services, for further investigations, management and advice on future mode of birth.', 4),
  ('00000000-0000-0000-0004-012007005000', '00000000-0000-0000-0003-012007000000', 'Demonstrates the ability to discuss and advise patients about postnatal contraception and administer/fit different contraceptive methods.', 5),
  ('00000000-0000-0000-0004-012007006000', '00000000-0000-0000-0003-012007000000', 'Uses support services appropriately, according to local provision, taking into account the wishes of the woman and her family.', 6),
  ('00000000-0000-0000-0004-012007007000', '00000000-0000-0000-0003-012007000000', 'Ensures effective handover and discharge to primary care.', 7),
  -- CiP_13_KS01 (7 descriptors)
  ('00000000-0000-0000-0004-013001001000', '00000000-0000-0000-0003-013001000000', 'Possesses knowledge of ethical and legal issues and an awareness of the situations where discrimination might occur.', 1),
  ('00000000-0000-0000-0004-013001002000', '00000000-0000-0000-0003-013001000000', 'Respects different values of patients and colleagues.', 2),
  ('00000000-0000-0000-0004-013001003000', '00000000-0000-0000-0003-013001000000', 'Recognises how health systems can discriminate against patients with protected characteristics and works to minimise this discrimination.', 3),
  ('00000000-0000-0000-0004-013001004000', '00000000-0000-0000-0003-013001000000', 'Must not allow their personal beliefs to lead to discrimination.', 4),
  ('00000000-0000-0000-0004-013001005000', '00000000-0000-0000-0003-013001000000', 'Adopts patient-centred assessments and interventions that are inclusive and respectful of diversity.', 5),
  ('00000000-0000-0000-0004-013001006000', '00000000-0000-0000-0003-013001000000', 'Is able to perform consultations addressing the specific needs of a disabled person and being mindful that not all disabilities are visible.', 6),
  ('00000000-0000-0000-0004-013001007000', '00000000-0000-0000-0003-013001000000', 'Understands the specific needs of transgender and nonbinary people and is able to perform consultations and refer appropriately to specialist services.', 7),
  -- CiP_13_KS02 (4 descriptors)
  ('00000000-0000-0000-0004-013002001000', '00000000-0000-0000-0003-013002000000', 'Understands the impact of a patient''s social, economic and environmental context on their health.', 1),
  ('00000000-0000-0000-0004-013002002000', '00000000-0000-0000-0003-013002000000', 'Interacts with appropriate patient representatives and engages with colleagues from different professional and personal backgrounds when working in MDT teams to promote the health of patients and the public.', 2),
  ('00000000-0000-0000-0004-013002003000', '00000000-0000-0000-0003-013002000000', 'Assesses the interaction between women''s health and cultural beliefs and practices.', 3),
  ('00000000-0000-0000-0004-013002004000', '00000000-0000-0000-0003-013002000000', 'Must be aware of and adhere to the legislation regarding certain cultural practices (e.g. Female Genital Mutilation (FGM), modern slavery) within the UK.', 4),
  -- CiP_13_KS03 (5 descriptors)
  ('00000000-0000-0000-0004-013003001000', '00000000-0000-0000-0003-013003000000', 'Takes an appropriate social history to identify any pertinent social issues and can signpost patients to appropriate services.', 1),
  ('00000000-0000-0000-0004-013003002000', '00000000-0000-0000-0003-013003000000', 'Considers the interaction between medical conditions, care and a woman''s broader work and family life.', 2),
  ('00000000-0000-0000-0004-013003003000', '00000000-0000-0000-0003-013003000000', 'Understands that people who care for dependents may face barriers in engaging with healthcare services or, as a result, have delayed engagement with healthcare providers which could impact on their health.', 3),
  ('00000000-0000-0000-0004-013003004000', '00000000-0000-0000-0003-013003000000', 'Understands the principles of safeguarding and their responsibility in protecting people''s health, wellbeing and human rights, and enabling them to live free from harm, abuse and neglect.', 4),
  ('00000000-0000-0000-0004-013003005000', '00000000-0000-0000-0003-013003000000', 'Enquires about the safety of a woman and her children and is able to act if they have a history of domestic abuse.', 5),
  -- CiP_13_KS04 (2 descriptors)
  ('00000000-0000-0000-0004-013004001000', '00000000-0000-0000-0003-013004000000', 'Understands how mental health issues can affect a woman''s reproductive health.', 1),
  ('00000000-0000-0000-0004-013004002000', '00000000-0000-0000-0003-013004000000', 'Knows how reproductive health issues can have a significant impact on the mental health of a woman and her partner.', 2),
  -- CiP_14_KS01 (3 descriptors)
  ('00000000-0000-0000-0004-014001001000', '00000000-0000-0000-0003-014001000000', 'Understands lifestyle factors which have an impact on someone''s short- and long-term health.', 1),
  ('00000000-0000-0000-0004-014001002000', '00000000-0000-0000-0003-014001000000', 'Provides appropriate lifestyle advice to women in a sensitive manner and facilitates access to useful support or services, e.g. smoking cessation, weight management, pelvic floor health and sexual health.', 2),
  ('00000000-0000-0000-0004-014001003000', '00000000-0000-0000-0003-014001000000', 'Contributes to developments, or education in, health promotion.', 3),
  -- CiP_14_KS02 (5 descriptors)
  ('00000000-0000-0000-0004-014002001000', '00000000-0000-0000-0003-014002000000', 'Understands the concept of screening.', 1),
  ('00000000-0000-0000-0004-014002002000', '00000000-0000-0000-0003-014002000000', 'Has an awareness of, and promotes, the current national screening programmes in women''s health.', 2),
  ('00000000-0000-0000-0004-014002003000', '00000000-0000-0000-0003-014002000000', 'Knows about the current recommended vaccinations available to protect women and their unborn children.', 3),
  ('00000000-0000-0000-0004-014002004000', '00000000-0000-0000-0003-014002000000', 'Is able to provide balanced advice regarding illness prevention strategies.', 4),
  ('00000000-0000-0000-0004-014002005000', '00000000-0000-0000-0003-014002000000', 'Is able to inform a patient about the impact of pregnancy and childbirth on their general, sexual and pelvic health and advise on mitigating strategies.', 5),
  -- CiP_14_KS03 (3 descriptors)
  ('00000000-0000-0000-0004-014003001000', '00000000-0000-0000-0003-014003000000', 'Is aware of the impact national policy has on local caregiving.', 1),
  ('00000000-0000-0000-0004-014003002000', '00000000-0000-0000-0003-014003000000', 'Is able to challenge and advocate to make sure local health and social care service provision equates with national standards.', 2),
  ('00000000-0000-0000-0004-014003003000', '00000000-0000-0000-0003-014003000000', 'Is aware of the interaction between the NHS and international healthcare bodies (e.g. the World Health Organization (WHO)).', 3),
  -- CiP_14_KS04 (2 descriptors)
  ('00000000-0000-0000-0004-014004001000', '00000000-0000-0000-0003-014004000000', 'Understands how the increasing movement of people and health migration impacts health services.', 1),
  ('00000000-0000-0000-0004-014004002000', '00000000-0000-0000-0003-014004000000', 'Is aware of the basic principles of global health.', 2)
